// Some portions generated by Co-Pilot
import React from "react";
import { render, screen, fireEvent, cleanup } from "@testing-library/react";
import { describe, it, expect, vi, afterEach } from "vitest";
import PlatformMatrix from "../index";

vi.mock("@/data/supported-platforms.json", () => ({
  default: {
    platforms: [
      {
        category: "Linux",
        distros: [
          {
            name: "Ubuntu 22.04 LTS",
            versions: {
              "21": { supported: true, docker: true },
              "17": { supported: true, docker: false },
              "11": { supported: false, docker: false },
            },
          },
          {
            name: "CentOS 7",
            versions: {
              "21": { supported: false, docker: false },
              "17": { supported: true, docker: false },
              "11": { supported: true, docker: true },
            },
          },
        ],
        footnotes: [
          "Some important note",
          "https://example.com for more details",
        ],
      },
      {
        category: "Windows",
        distros: [
          {
            name: "Windows 11",
            versions: {
              "21": { supported: true, docker: false },
              "17": { supported: true, docker: false },
            },
          },
        ],
      },
    ],
  },
}));

describe("PlatformMatrix", () => {
  afterEach(() => {
    cleanup();
  });

  it("renders platform categories", () => {
    render(<PlatformMatrix />);
    expect(screen.getByText("Linux")).toBeTruthy();
    expect(screen.getByText("Windows")).toBeTruthy();
  });

  it("renders legend icons", () => {
    render(<PlatformMatrix />);
    expect(screen.getByText("Supported")).toBeTruthy();
    expect(screen.getByText("Docker Available")).toBeTruthy();
    expect(screen.getByText("Not Supported")).toBeTruthy();
  });

  it("toggles accordion on category click", () => {
    render(<PlatformMatrix />);
    const linuxButton = screen.getByText("Linux").closest("button");
    expect(linuxButton).toBeTruthy();
    fireEvent.click(linuxButton!);
    // After clicking, the distro content should be visible (may appear in both desktop/mobile)
    const ubuntuEls = screen.queryAllByText("Ubuntu 22.04 LTS");
    expect(ubuntuEls.length).toBeGreaterThan(0);
  });

  it("shows footnotes when accordion is open", () => {
    render(<PlatformMatrix />);
    const linuxButton = screen.getByText("Linux").closest("button");
    fireEvent.click(linuxButton!);
    expect(screen.getByText("Some important note")).toBeTruthy();
  });

  it("renders footnote links correctly", () => {
    render(<PlatformMatrix />);
    const linuxButton = screen.getByText("Linux").closest("button");
    fireEvent.click(linuxButton!);
    const link = screen.getByRole("link", { name: /example.com/i });
    expect(link).toBeTruthy();
    expect(link.getAttribute("href")).toBe("https://example.com");
  });

  it("closes accordion when clicking again", () => {
    render(<PlatformMatrix />);
    const linuxButton = screen.getByText("Linux").closest("button");
    fireEvent.click(linuxButton!); // open
    fireEvent.click(linuxButton!); // close
    // Content should collapse - Ubuntu is still in DOM due to conditional render pattern
    expect(screen.queryByText("Ubuntu 22.04 LTS")).toBeNull();
  });

  it("only one category open at a time", () => {
    render(<PlatformMatrix />);
    const linuxButton = screen.getByText("Linux").closest("button");
    const windowsButton = screen.getByText("Windows").closest("button");
    fireEvent.click(linuxButton!);
    const ubuntuEls = screen.queryAllByText("Ubuntu 22.04 LTS");
    expect(ubuntuEls.length).toBeGreaterThan(0);
    fireEvent.click(windowsButton!);
    // Linux content should now be hidden
    expect(screen.queryByText("Ubuntu 22.04 LTS")).toBeNull();
    const windowsEls = screen.queryAllByText("Windows 11");
    expect(windowsEls.length).toBeGreaterThan(0);
  });
});
